 1	import {
 2	  type Dispatch,
 3	  type FC,
 4	  type MouseEvent as ReactMouseEvent,
 5	  type SetStateAction,
 6	  useState,
 7	} from 'react';
 8	
 9	import { FormGroup, Select as PfSelect, SelectOption } from '@patternfly/react-core';
10	import { useForkliftTranslation } from '@utils/i18n';
11	import selectToggle from '@utils/selectToggle';
12	
13	import { AFFINITY_CONDITION_LABELS } from './utils/constants';
14	import type { AffinityRowData } from './utils/types';
15	
16	type AffinityConditionSelectProps = {
17	  focusedAffinity: AffinityRowData;
18	  setFocusedAffinity: Dispatch<SetStateAction<AffinityRowData>>;
19	};
20	
21	const AffinityConditionSelect: FC<AffinityConditionSelectProps> = ({
22	  focusedAffinity,
23	  setFocusedAffinity,
24	}) => {
25	  const { t } = useForkliftTranslation();
26	
27	  const [isOpen, setIsOpen] = useState(false);
28	
29	  const handleChange = (event: ReactMouseEvent | undefined, value: string | number | undefined) => {
30	    event?.preventDefault();
31	    setFocusedAffinity({ ...focusedAffinity, condition: value });
32	    setIsOpen(false);
33	  };
34	
35	  const onToggle = () => {
36	    setIsOpen((prevIsOpen) => !prevIsOpen);
37	  };
38	
39	  return (
40	    <FormGroup fieldId="condition" isRequired label={t('Condition')}>
41	      <PfSelect
42	        toggle={selectToggle({
43	          isExpanded: isOpen,
44	          onClick: onToggle,
45	          selected: AFFINITY_CONDITION_LABELS[focusedAffinity?.condition],
46	          testId: 'affinity-condition-select',
47	        })}
48	        isOpen={isOpen}
49	        onSelect={handleChange}
50	        selected={focusedAffinity?.condition}
51	      >
52	        {Object.entries(AFFINITY_CONDITION_LABELS).map(([key, value]) => (
53	          <SelectOption key={key} value={key}>
54	            {value}
55	          </SelectOption>
56	        ))}
57	      </PfSelect>
58	    </FormGroup>
59	  );
60	};
61	
62	export default AffinityConditionSelect;

