 1	import type { ReactNode, Ref } from 'react';
 2	
 3	import { MenuToggle, type MenuToggleElement, type MenuToggleProps } from '@patternfly/react-core';
 4	
 5	type selectToggleProps = MenuToggleProps & {
 6	  testId?: string;
 7	  selected: ReactNode;
 8	};
 9	
10	const selectToggle = ({ selected, testId, ...menuProps }: selectToggleProps) => {
11	  return (toggleRef: Ref<MenuToggleElement>) => (
12	    <MenuToggle data-testid={testId} ref={toggleRef} {...menuProps}>
13	      {selected}
14	    </MenuToggle>
15	  );
16	};
17	
18	export default selectToggle;

